        opt = false
      }
      parts.push(any
        ? min < 2
          ? min < 1
            ? '(?:/[^/]+)*'
            : '(?:/[^/]+)+'
          : `(?:/[^/]+){${min},}`
        : max === 1
          ? min === 1
            ? '/[^/]+'
            : '(?:/[^/]+)?'
          : min === max
            ? `(?:/[^/]+){${min}}`
            : `(?:/[^/]+){${min},${max}}`)
