    min = 0
    max = 0
    any = false
  }
  function finalise (): string {
    flatten(true)
    return (opt ? '^/$|^' : '^') + parts.reduce((acc, seg) => seg + acc, '$')
  }
  for (const part of spec.split('/').slice(1).reverse()) {
    switch (part) {
      case '+':
        min++
        max++
        break
      case '++':
        max++
        break
      case '*':
        min++
        any = true
        break
      case '**':
        any = true
        break
      default:
        flatten()
        opt = false
        if (part.match(/:.+/) !== null) {
          props.push(part.slice(1))
          parts.push('/([^/]+)')
